use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use tokio::time::{sleep, Duration};

async fn worker(stop: Arc<AtomicBool>, id: u32) {
    loop {
        if stop.load(Ordering::Relaxed) {
            println!("worker {} stopping", id);
            break;
        }
        // BUG: while sleeping, the task never polls the stop flag
        sleep(Duration::from_secs(10)).await;
        println!("worker {} tick", id);
    }
}

#[tokio::main]
async fn main() {
    let stop = Arc::new(AtomicBool::new(false));
    let s = Arc::clone(&stop);
    let task = tokio::spawn(worker(s, 1));

    sleep(Duration::from_millis(50)).await;
    stop.store(true, Ordering::Relaxed);
    // task is stuck sleeping for 10 seconds and won't check the flag
    task.await.unwrap();
}

error_message:
// No compile error. The worker never wakes to check the flag because
// it's blocked in sleep(Duration::from_secs(10)).await — there's no
// mechanism to interrupt an awaiting future when a flag changes.

