use tokio_util::sync::CancellationToken;
use tokio::time::{sleep, Duration};

async fn worker(token: CancellationToken, id: u32) {
    loop {
        tokio::select! {
            biased;
            _ = token.cancelled() => {
                println!("worker {} received cancellation", id);
                break;
            }
            _ = sleep(Duration::from_millis(200)) => {
                println!("worker {} tick", id);
            }
        }
    }
}

#[tokio::main]
async fn main() {
    let token = CancellationToken::new();

    let t1 = tokio::spawn(worker(token.clone(), 1));
    let t2 = tokio::spawn(worker(token.clone(), 2));

    sleep(Duration::from_millis(450)).await;
    println!("cancelling all workers...");
    token.cancel();  // instantly wakes all tasks awaiting token.cancelled()

    let _ = tokio::join!(t1, t2);
    println!("all workers stopped");
}

