use tokio_util::sync::CancellationToken;
use tokio::{signal, time::{sleep, Duration}};

async fn worker(token: CancellationToken, id: u32) {
    loop {
        tokio::select! {
            biased;
            _ = token.cancelled() => {
                println!("worker {} shutting down gracefully", id);
                // do cleanup here (flush buffers, close connections, etc.)
                break;
            }
            _ = sleep(Duration::from_millis(100)) => {
                println!("worker {} alive", id);
            }
        }
    }
}

#[tokio::main]
async fn main() {
    let token = CancellationToken::new();

    let t1 = tokio::spawn(worker(token.clone(), 1));
    let t2 = tokio::spawn(worker(token.clone(), 2));

    // Wait for Ctrl+C then cancel all tasks
    signal::ctrl_c().await.unwrap();
    println!("\nreceived ctrl+c, cancelling workers...");
    token.cancel();

    // Wait for clean shutdown
    let _ = tokio::join!(t1, t2);
    println!("shutdown complete");
}

