use tokio::time::{timeout, Duration};

async fn long_operation() -> String {
    // Simulate work that takes variable time
    tokio::time::sleep(Duration::from_millis(200)).await;
    String::from("result")
}

async fn cleanup() {
    println!("cleaning up resources...");
    // flush buffers, close connections, etc.
    tokio::time::sleep(Duration::from_millis(10)).await;
}

#[tokio::main]
async fn main() {
    // timeout() drops the future immediately on expiry — no cleanup runs
    match timeout(Duration::from_millis(100), long_operation()).await {
        Ok(result) => println!("completed: {}", result),
        Err(_) => {
            println!("timed out — but cleanup never ran!");
            // cleanup() is never called
        }
    }
}

fixed_code:
use tokio_util::sync::CancellationToken;
use tokio::time::{sleep, Duration};

async fn long_operation(token: CancellationToken) -> Option<String> {
    tokio::select! {
        biased;
        _ = token.cancelled() => {
            // Cleanup runs here before returning
            println!("operation cancelled, cleaning up...");
            sleep(Duration::from_millis(10)).await;  // async cleanup allowed
            None
        }
        result = async {
            sleep(Duration::from_millis(200)).await;
            String::from("result")
        } => Some(result)
    }
}

#[tokio::main]
async fn main() {
    let token = CancellationToken::new();
    let op_token = token.clone();

    let task = tokio::spawn(long_operation(op_token));

    // Cancel after 100ms deadline
    sleep(Duration::from_millis(100)).await;
    token.cancel();

    match task.await.unwrap() {
        Some(result) => println!("completed: {}", result),
        None => println!("cancelled after cleanup"),
    }
}

