use tokio_util::sync::CancellationToken;
use tokio::time::{sleep, Duration};

async fn batch_process(count: u32) -> Vec<i32> {
    let mut results = Vec::new();
    for i in 0..count {
        // BUG: each iteration takes 50ms, but we never check for cancellation
        sleep(Duration::from_millis(50)).await;
        results.push(i as i32 * 2);
    }
    results
}

#[tokio::main]
async fn main() {
    let token = CancellationToken::new();
    let t = token.clone();

    // run_until_cancelled wraps the future but can only cancel at await points
    // where the future cooperates
    let task = tokio::spawn(async move {
        token.run_until_cancelled(batch_process(20)).await
    });

    sleep(Duration::from_millis(75)).await;
    t.cancel();
    // Task won't stop until the current 50ms sleep finishes
    println!("{:?}", task.await.unwrap());
}

error_message:
// No compile error. The task responds to cancellation only at the granularity
// of each 50ms sleep — cancellation latency equals the longest await point
// inside batch_process.

fixed_code:
use tokio_util::sync::CancellationToken;
use tokio::time::{sleep, Duration};

async fn batch_process(token: CancellationToken, count: u32) -> Vec<i32> {
    let mut results = Vec::new();
    for i in 0..count {
        // Check for cancellation at the START of each iteration
        if token.is_cancelled() {
            println!("batch cancelled after {} items", results.len());
            break;
        }
        sleep(Duration::from_millis(50)).await;
        results.push(i as i32 * 2);
    }
    results
}

#[tokio::main]
async fn main() {
    let token = CancellationToken::new();
    let work_token = token.clone();
    let cancel_token = token.clone();

    let task = tokio::spawn(batch_process(work_token, 20));

    sleep(Duration::from_millis(75)).await;
    cancel_token.cancel();

    let results = task.await.unwrap();
    println!("processed {} items: {:?}", results.len(), results);
}
